const items = $input.all();
let spreadsheet_id = '';
let spreadsheet_url = '';

for (const item of items) {
  // Direktes spreadsheetId aus Google Sheets Create Response
  if (item.json.spreadsheetId) {
    spreadsheet_id = item.json.spreadsheetId;
    spreadsheet_url = item.json.spreadsheetUrl || '';
    break;
  }
  // Gesetzte spreadsheet_id
  if (item.json.spreadsheet_id && item.json.spreadsheet_id.length > 20) {
    spreadsheet_id = item.json.spreadsheet_id;
    break;
  }
  // Aus URL extrahieren
  if (item.json.spreadsheet_url) {
    spreadsheet_url = item.json.spreadsheet_url;
    const match = item.json.spreadsheet_url.match(/\/spreadsheets\/d\/([a-zA-Z0-9_-]+)/);
    if (match) {
      spreadsheet_id = match[1];
      break;
    }
  }
}

if (!spreadsheet_id) {
  throw new Error('Spreadsheet-ID konnte nicht aus WF1-Output extrahiert werden. Items: ' + JSON.stringify(items.map(i => Object.keys(i.json))));
}

return [{
  json: {
    spreadsheet_id,
    spreadsheet_url: spreadsheet_url || `https://docs.google.com/spreadsheets/d/${spreadsheet_id}/edit`,
    status: 'wf1_complete'
  }
}];

const contentItems = $input.all();
let seoContent = '';

for (const item of contentItems) {
  const text = item.json.content_final || item.json.content_humanized || item.json.content_raw || '';
  if (text && text.trim()) {
    seoContent += text + '\n\n';
  }
}

// Auf max 12000 Zeichen begrenzen
if (seoContent.length > 12000) {
  seoContent = seoContent.slice(0, 12000) + '\n...[gekuerzt]';
}

const originalContent = ($('Variablen setzen').first().json.original_content || '').slice(0, 6000);
const keyword = $('Variablen setzen').first().json.keyword || '';
const url = $('Variablen setzen').first().json.url || '';
const spreadsheetData = $('Spreadsheet-ID extrahieren').first().json;

return [{
  json: {
    seo_content: seoContent || '[Kein SEO-Content gefunden]',
    original_content: originalContent,
    keyword,
    url,
    spreadsheet_id: spreadsheetData.spreadsheet_id,
    spreadsheet_url: spreadsheetData.spreadsheet_url
  }
}];

