parameters.jsCode:
const aiResponse = $input.first().json;
const contentData = $('SEO Content aufbereiten').first().json;
const vars = $('Variablen setzen').first().json;

const keyword = contentData.keyword || vars.keyword || '';
const url = contentData.url || vars.url || '';
const spreadsheet_id = contentData.spreadsheet_id || '';
const spreadsheet_url = contentData.spreadsheet_url || '';
const email_empfaenger = vars.email_empfaenger || '';

// KI-Antwort parsen
let analysisResult = {};
try {
  const raw = aiResponse.choices?.[0]?.message?.content || '{}';
  analysisResult = JSON.parse(raw);
} catch (e) {
  analysisResult = {
    aehnlichkeit_prozent: 0,
    status: 'fehler',
    fehlende_ueberschriften: [],
    inhaltliche_luecken: [`Analyse-Fehler: ${e.message}`],
    staerken_bestehender_content: [],
    zusammenfassung: 'Die automatische Analyse konnte nicht abgeschlossen werden.'
  };
}

const aehnlichkeit = Number(analysisResult.aehnlichkeit_prozent) || 0;
const istIdentisch = aehnlichkeit >= 90;
const status = istIdentisch ? 'identisch' : 'verbesserbar';

const fehlende_ueberschriften = (analysisResult.fehlende_ueberschriften || []);
const inhaltliche_luecken = (analysisResult.inhaltliche_luecken || []);
const staerken = (analysisResult.staerken_bestehender_content || []);
const zusammenfassung = analysisResult.zusammenfassung || '';

// ---- EMAIL HTML aufbauen ----
const statusColor = istIdentisch ? '#22c55e' : '#f59e0b';
const statusIcon = istIdentisch ? '✓' : '⚠';
const statusLabel = istIdentisch ? 'Identisch — Kein Handlungsbedarf' : 'Verbesserbar — Optimierungen empfohlen';

const listItems = (arr) => arr.length > 0
  ? '<ul style="margin:8px 0;padding-left:20px;">' + arr.map(i => `<li style="margin-bottom:6px;">${i}</li>`).join('') + '</ul>'
  : '<p style="color:#6b7280;">—</p>';

let emailBody = `<!DOCTYPE html><html><body style="font-family:system-ui,-apple-system,sans-serif;max-width:680px;margin:0 auto;padding:32px 24px;color:#1f2937;background:#ffffff;">
<div style="border-bottom:3px solid ${statusColor};padding-bottom:16px;margin-bottom:24px;">
  <h1 style="margin:0;font-size:22px;color:#111827;">SEO Content Audit Report</h1>
  <p style="margin:4px 0 0;color:#6b7280;font-size:14px;">Automatisch generiert — ${new Date().toLocaleDateString('de-DE', {day:'2-digit',month:'long',year:'numeric'})}</p>
</div>

<table style="width:100%;border-collapse:collapse;margin-bottom:28px;border-radius:8px;overflow:hidden;border:1px solid #e5e7eb;">
  <tr style="background:#f9fafb;"><td style="padding:12px 16px;font-weight:600;font-size:13px;color:#6b7280;text-transform:uppercase;letter-spacing:0.05em;width:160px;">Keyword</td><td style="padding:12px 16px;font-size:15px;font-weight:600;">${keyword}</td></tr>
  <tr><td style="padding:12px 16px;font-weight:600;font-size:13px;color:#6b7280;text-transform:uppercase;letter-spacing:0.05em;">Analysierte URL</td><td style="padding:12px 16px;"><a href="${url}" style="color:#2563eb;word-break:break-all;">${url}</a></td></tr>
  <tr style="background:#f9fafb;"><td style="padding:12px 16px;font-weight:600;font-size:13px;color:#6b7280;text-transform:uppercase;letter-spacing:0.05em;">Ähnlichkeit</td><td style="padding:12px 16px;font-size:24px;font-weight:700;color:${statusColor};">${aehnlichkeit}%</td></tr>
  <tr><td style="padding:12px 16px;font-weight:600;font-size:13px;color:#6b7280;text-transform:uppercase;letter-spacing:0.05em;">Bewertung</td><td style="padding:12px 16px;"><span style="background:${statusColor};color:white;padding:4px 14px;border-radius:20px;font-size:13px;font-weight:600;">${statusIcon} ${statusLabel}</span></td></tr>
</table>

<h2 style="font-size:16px;color:#374151;margin-bottom:8px;">Einschätzung</h2>
<p style="background:#f9fafb;border-left:4px solid ${statusColor};padding:12px 16px;border-radius:0 6px 6px 0;margin:0 0 24px;line-height:1.6;">${zusammenfassung || 'Keine Zusammenfassung verfügbar.'}</p>
`;

if (!istIdentisch) {
  emailBody += `<h2 style="font-size:16px;color:#374151;margin-bottom:8px;">📝 Vorschläge: Fehlende/anzupassende Überschriften</h2>${listItems(fehlende_ueberschriften)}<h2 style="font-size:16px;color:#374151;margin-top:24px;margin-bottom:8px;">📋 Inhaltliche Ergänzungen</h2>${listItems(inhaltliche_luecken)}`;
} else {
  emailBody += `<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:16px;margin-bottom:24px;"><p style="margin:0;color:#15803d;font-weight:600;">✓ Der bestehende Content deckt das Keyword bereits optimal ab.</p><p style="margin:8px 0 0;color:#166534;">Keine Änderungen oder Ergänzungen empfohlen.</p></div>`;
}

if (staerken.length > 0) {
  emailBody += `<h2 style="font-size:16px;color:#374151;margin-top:24px;margin-bottom:8px;">💪 Stärken des bestehenden Contents</h2>${listItems(staerken)}`;
}

if (spreadsheet_url) {
  emailBody += `<div style="margin-top:32px;padding-top:20px;border-top:1px solid #e5e7eb;"><a href="${spreadsheet_url}" style="display:inline-block;background:#2563eb;color:white;padding:10px 20px;border-radius:6px;text-decoration:none;font-weight:600;">📊 Vollständiges SEO-Report Google Sheet öffnen →</a></div>`;
}

emailBody += `<p style="margin-top:32px;color:#9ca3af;font-size:12px;">SEO Content Audit | Automatisch generiert vom SEO Content Agent</p></body></html>`;

return [{
  json: {
    keyword,
    url,
    spreadsheet_id,
    spreadsheet_url,
    email_empfaenger,
    aehnlichkeit_prozent: aehnlichkeit,
    status,
    fehlende_ueberschriften: fehlende_ueberschriften.join('\n'),
    inhaltliche_luecken: inhaltliche_luecken.join('\n'),
    staerken: staerken.join('\n'),
    zusammenfassung,
    email_body: emailBody,
    email_subject: `SEO Audit: "${keyword}" — ${aehnlichkeit}% Ähnlichkeit (${status})`
  }
}];
